package main

import (
	"fmt"
)

func parity(b uint8) uint8 {
	b ^= (b >> 4)
	b ^= (b >> 2)
	b ^= (b >> 1)
	return (b & 1)
}

func convolve(sequence []uint8, G0, G1 uint8) []uint8 {
	res := make([]uint8, 0)
	var state uint8 = 0
	for _, bit := range sequence {
		state = (state << 1) | bit
		res = append(res, parity(state&G0))
		res = append(res, parity(state&G1))
	}

	for range 4 {
		state = (state << 1)
		res = append(res, parity(state&G0))
		res = append(res, parity(state&G1))
	}

	return res
}

func convertAsBits(sequence []uint8) []uint8 {
	res := make([]uint8, 0)
	for _, b := range sequence {
		for i := range 8 {
			bit := (b >> (7 - i)) & 1
			res = append(res, uint8(bit))
		}
	}
	return res
}

func main() {
	x:=""
	flag := ""
	var G0 uint8 = 0x19
	var G1 uint8 = 0x1B
	for {
		found := false
		for i := 48; i <= 125; i++ {
			test := append([]byte{}, []byte(flag)...)
			test = append(test, byte(i))
			y := convertAsBits(test)
			z := convolve(y, G0, G1)
			zStr := ""
			for _, b := range z {
				zStr += fmt.Sprintf("%d", b)
			}
			if zStr[:16*len(test)] == x[:16*len(test)] {
				flag = flag + string(rune(i))
				found = true
				break
			}
		}
		if !found {
			break
		}
	}
fmt.Println(flag)
}
